import React, { useEffect, useRef } from "react";

const GoogleButton = ({ onSuccess, onError, buttonText }) => {
  const buttonRef = useRef(null);

  useEffect(() => {
    if (!window.google) {
      const script = document.createElement("script");
      script.src = "https://accounts.google.com/gsi/client";
      script.async = true;
      script.onload = () => {
        if (window.google && buttonRef.current) {
          window.google.accounts.id.initialize({
            client_id: "YOUR_GOOGLE_CLIENT_ID",
            callback: onSuccess,
          });
          window.google.accounts.id.renderButton(buttonRef.current, {
            theme: "outline",
            size: "large",
            text: buttonText ? "signin_with" : undefined,
            type: buttonText ? "standard" : undefined,
          });
          if (buttonText && buttonRef.current) {
            const btn = buttonRef.current.querySelector("div[role=button]");
            if (btn) btn.innerText = buttonText;
          }
        }
      };
      document.body.appendChild(script);
    } else if (window.google && buttonRef.current) {
      window.google.accounts.id.initialize({
        client_id: "YOUR_GOOGLE_CLIENT_ID",
        callback: onSuccess,
      });
      window.google.accounts.id.renderButton(buttonRef.current, {
        theme: "outline",
        size: "large",
        text: buttonText ? "signin_with" : undefined,
        type: buttonText ? "standard" : undefined,
      });
      if (buttonText && buttonRef.current) {
        const btn = buttonRef.current.querySelector("div[role=button]");
        if (btn) btn.innerText = buttonText;
      }
    }
  }, [onSuccess, buttonText]);

  return <div ref={buttonRef}></div>;
};

export default GoogleButton;
